# ══════════════════════════════════════════════════════════════════════════════
# Helpers runtime
# ══════════════════════════════════════════════════════════════════════════════

def _f_hat(n: int) -> float:
    if n <= 1: return 1.0
    if n == 2: return 1.5
    if n == 3: return 2.0
    return max(1.0, math.log2(n) * 0.5 + 0.8)


def _normalize(candidates: list[str], probs: dict[str, float]) -> dict[str, float]:
    raw = {w: probs.get(w, 1e-10) for w in candidates}
    total = sum(raw.values())
    if total == 0:
        return {w: 1.0 / len(candidates) for w in candidates}
    return {w: v / total for w, v in raw.items()}


def _expected_score(guess_word: str,
                    candidates: list[str],
                    weights: dict[str, float],
                    wl: int) -> float:
    win_pat = tuple([2] * wl)
    partition: dict[tuple, list[str]] = defaultdict(list)
    for w in candidates:
        partition[feedback(w, guess_word)].append(w)
    total_w = sum(weights.get(w, 0.0) for w in candidates) or 1.0
    score = 0.0
    for pat, group in partition.items():
        p_f = sum(weights.get(w, 0.0) for w in group) / total_w
        score += p_f * (1.0 if pat == win_pat else 1.0 + _f_hat(len(group)))
    return score


def _gen_probe_nonwords(candidates: list[str], wl: int, n: int = 15) -> list[str]:
    """
    No-palabras sonda orientadas a las letras ambiguas entre candidatos.
    Útil cuando el mejor guess está fuera del conjunto de candidatos.
    """
    ambiguous: set[str] = set()
    pos_sets = [set() for _ in range(wl)]
    for w in candidates:
        for i, ch in enumerate(w):
            pos_sets[i].add(ch)
    for s in pos_sets:
        if len(s) > 1:
            ambiguous.update(s)

    # Complementar con letras frecuentes si faltan
    all_letters: dict[str, int] = defaultdict(int)
    for w in candidates:
        for ch in set(w):
            all_letters[ch] += 1
    for ch, _ in sorted(all_letters.items(), key=lambda x: -x[1]):
        ambiguous.add(ch)
        if len(ambiguous) >= wl + 3:
            break

    pool = list(ambiguous)[:wl + 3]
    cand_set = set(candidates)
    non_words, seen = [], set()
    for combo in itertools.permutations(pool, wl):
        nw = ''.join(combo)
        if len(set(nw)) == wl and nw not in seen and nw not in cand_set:
            seen.add(nw)
            non_words.append(nw)
        if len(non_words) >= n:
            break
    return non_words


def _endgame_best(candidates: list[str],
                  guesses_left: int,
                  probs: dict[str, float],
                  wl: int) -> str:
    """
    End-game T5+: si candidatos > intentos restantes, busca sonda
    desambiguadora que maximice candidatos en grupos de tamaño 1.
    """
    if len(candidates) == 1:
        return candidates[0]
    if guesses_left >= len(candidates):
        return max(candidates, key=lambda w: probs.get(w, 0.0))
    if guesses_left == 1:
        return max(candidates, key=lambda w: probs.get(w, 0.0))

    # guesses_left == 2, len >= 3: buscar sonda perfecta
    probe_pool = candidates + _gen_probe_nonwords(candidates, wl, n=30)
    weights = _normalize(candidates, probs)

    best_probe = candidates[0]
    best_singletons = -1
    best_score = float('inf')

    for probe in probe_pool:
        partition: dict[tuple, list[str]] = defaultdict(list)
        for w in candidates:
            partition[feedback(w, probe)].append(w)
        singletons = sum(1 for g in partition.values() if len(g) == 1)
        s = _expected_score(probe, candidates, weights, wl)
        if singletons > best_singletons or (singletons == best_singletons and s < best_score):
            best_singletons = singletons
            best_score = s
            best_probe = probe
        if best_singletons == len(candidates):
            break

    return best_probe


# ══════════════════════════════════════════════════════════════════════════════
# Estrategia principal
# ══════════════════════════════════════════════════════════════════════════════

class GRStrat(Strategy):

    @property
    def name(self) -> str:
        return "GRStrat_gabriel_regina"

    def begin_game(self, config: GameConfig) -> None:
        self._vocab     = list(config.vocabulary)
        self._vocab_set = set(config.vocabulary)
        self._probs     = config.probabilities
        self._wl        = config.word_length
        self._mode      = config.mode
        self._max_g     = config.max_guesses

        openers = OPENERS_UNIFORM if config.mode == "uniform" else OPENERS_FREQ
        self._opener = openers.get(config.word_length, self._vocab[0])
        self._t2 = T2_TABLES.get(config.word_length, {}).get(config.mode, {})
        self._t3 = T3_TABLES.get(config.word_length, {}).get(config.mode, {})
        self._t4 = T4_TABLES.get(config.word_length, {}).get(config.mode, {})

    def guess(self, history: list[tuple[str, tuple[int, ...]]]) -> str:
        turn = len(history) + 1
        guesses_left = self._max_g - len(history)

        # ── T1 ────────────────────────────────────────────────────────────────
        if turn == 1:
            return self._opener

        # ── Filtrar candidatos ─────────────────────────────────────────────────
        candidates = self._vocab
        for g, pat in history:
            candidates = filter_candidates(candidates, g, pat)

        if not candidates:
            return self._vocab[0]
        if len(candidates) == 1:
            return candidates[0]
        if len(candidates) == 2:
            return max(candidates, key=lambda w: self._probs.get(w, 0.0))

        # ── End-game (prioridad absoluta) ──────────────────────────────────────
        if guesses_left <= 2 and len(candidates) > guesses_left:
            return _endgame_best(candidates, guesses_left, self._probs, self._wl)

        # ── T2: lookup tabla ──────────────────────────────────────────────────
        if turn == 2:
            pat1_str = ''.join(str(x) for x in history[0][1])
            if pat1_str in self._t2:
                return self._t2[pat1_str]
            return self._dynamic_best(candidates)

        # ── T3: lookup tabla + fallback mejorado ──────────────────────────────
        if turn == 3:
            pat1_str = ''.join(str(x) for x in history[0][1])
            guess2   = history[1][0]
            pat2_str = ''.join(str(x) for x in history[1][1])
            key = f"{pat1_str}|{guess2}|{pat2_str}"
            if key in self._t3:
                return self._t3[key]
            return self._dynamic_best(candidates)

        # ── T4: lookup tabla (si existe) + fallback mejorado ──────────────────
        if turn == 4 and self._t4:
            pat1_str = ''.join(str(x) for x in history[0][1])
            g2       = history[1][0]
            pat2_str = ''.join(str(x) for x in history[1][1])
            g3       = history[2][0]
            pat3_str = ''.join(str(x) for x in history[2][1])
            key = f"{pat1_str}|{g2}|{pat2_str}|{g3}|{pat3_str}"
            if key in self._t4:
                return self._t4[key]

        # ── T4+ dinámico ──────────────────────────────────────────────────────
        return self._dynamic_best(candidates)

    def _dynamic_best(self, candidates: list[str]) -> str:
        """
        Fallback dinámico mejorado.

        Si quedan >3 candidatos: evalúa el vocabulario completo + no-palabras
        sonda. El mejor guess puede estar fuera del conjunto de candidatos
        (una palabra que separa el grupo aunque no sea la respuesta).

        Si quedan ≤3 candidatos: evalúa solo candidatos (trivial, ya óptimo).
        """
        weights = _normalize(candidates, self._probs)

        if len(candidates) <= 3:
            # Con ≤3 candidatos, evaluar solo candidatos es óptimo
            pool = candidates
        else:
            # Con >3, evaluar vocabulario completo + no-palabras sonda
            # Cap en 400 para mantener tiempo bajo control (<0.1s)
            vocab_sample = self._vocab[:400] if len(self._vocab) > 400 else self._vocab
            probes = _gen_probe_nonwords(candidates, self._wl, n=20)
            pool = list(set(vocab_sample + probes))

        best, best_s = candidates[0], float('inf')
        for g in pool:
            s = _expected_score(g, candidates, weights, self._wl)
            if s < best_s:
                best_s = s
                best = g
        return best